#include <stdio.h>
#include <stdlib.h>
#include <math.h>

// Function to calculate GCD
int gcd(int a, int b) {
    if (b == 0)
        return a;
    return gcd(b, a % b);
}

// Function to calculate the expected value of GCD
long long calculateExpectedValue(int A[], int B[], int K) {
    long long sum = 0;
    long long total = 1;
    for (int i = 0; i < K; i++) {
        total *= (B[i] - A[i] + 1);
    }
    for (int i = A[0]; i <= B[0]; i++) {
        for (int j = A[1]; j <= B[1]; j++) {
            int g = gcd(i, j);
            for (int k = 2; k < K; k++) {
                for (int l = A[k]; l <= B[k]; l++) {
                    g = gcd(g, l);
                }
            }
            sum += g;
        }
    }
    return sum;
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int K;
        scanf("%d", &K);
        int A[K], B[K];
        for (int i = 0; i < K; i++) {
            scanf("%d %d", &A[i], &B[i]);
        }
        long long expectedValue = calculateExpectedValue(A, B, K);
        long long total = 1;
        for (int i = 0; i < K; i++) {
            total *= (B[i] - A[i] + 1);
        }
        long long P = expectedValue;
        long long Q = total;
        long long N = (1000000007 - P % Q) * powMod(Q, 1000000007 - 2, 1000000007) % 1000000007;
        printf("%lld\n", N);
    }
    return 0;
}

