import java.util.Scanner;
public class Main {
    // Function to calculate GCD
    public static int gcd(int a, int b) {
        if (b == 0)
            return a;
        return gcd(b, a % b);
    }

    // Function to calculate the expected value of GCD
    public static long calculateExpectedValue(int[] A, int[] B, int K) {
        long sum = 0;
        long total = 1;
        for (int i = 0; i < K; i++) {
            total *= (B[i] - A[i] + 1);
        }
        for (int i = A[0]; i <= B[0]; i++) {
            for (int j = A[1]; j <= B[1]; j++) {
                int g = gcd(i, j);
                for (int k = 2; k < K; k++) {
                    for (int l = A[k]; l <= B[k]; l++) {
                        g = gcd(g, l);
                    }
                }
                sum += g;
            }
        }
        return sum;
    }

    public static long powMod(long a, long b, long mod) {
        long res = 1;
        while (b > 0) {
            if (b % 2 == 1)
                res = res * a % mod;
            a = a * a % mod;
            b >>= 1;
        }
        return res;
    }

    public static long modInverse(long a, long m) {
        return powMod(a, m - 2, m);
    }

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int T = scanner.nextInt();
        while (T-- > 0) {
            int K = scanner.nextInt();
            int[] A = new int[K];
            int[] B = new int[K];
            for (int i = 0; i < K; i++) {
                A[i] = scanner.nextInt();
                B[i] = scanner.nextInt();
            }
            long expectedValue = calculateExpectedValue(A, B, K);
            long total = 1;
            for (int i = 0; i < K; i++) {
                total *= (B[i] - A[i] + 1);
            }
            long P = expectedValue;
            long Q = total;
            long N = (1000000007 - P % Q) * modInverse(Q, 1000000007) % 1000000007;
            System.out.println(N);
        }
    }
}

